	if (enables.length > 0) chainParts.push("Enables: " + enables.map((slug) => `<a href="#${escHtml(slug)}" class="chain-ref">${escHtml(slugToTitle?.[slug] || slug)}</a>`).join(", "));
	if (enabledBy.length > 0) chainParts.push("Enabled by: " + enabledBy.map((slug) => `<a href="#${escHtml(slug)}" class="chain-ref">${escHtml(slugToTitle?.[slug] || slug)}</a>`).join(", "));
	if (related.length > 0) chainParts.push("Related: " + related.map((slug) => `<a href="#${escHtml(slug)}" class="chain-ref">${escHtml(slugToTitle?.[slug] || slug)}</a>`).join(", "));
	const sidenoteHtml = chainParts.length > 0 ? `\n        <span class="sidenote">${chainParts.join("<br>")}</span>` : "";
